import{_ as e,o as t,c as s,Q as a}from"./chunks/framework.2275ac6f.js";const u=JSON.parse('{"title":"网络安全协议与VPN","description":"","frontmatter":{"title":"网络安全协议与VPN","date":"2021-05-21T10:41:04.000Z","tags":["信息安全"],"published":true,"hideInList":false,"feature":null,"isTop":false},"headers":[{"level":2,"title":"VPN是什么","slug":"vpn是什么","link":"#vpn是什么","children":[]},{"level":2,"title":"SSL/TLS","slug":"ssl-tls","link":"#ssl-tls","children":[]},{"level":2,"title":"IPSec(AH/ESP)","slug":"ipsec-ah-esp","link":"#ipsec-ah-esp","children":[]},{"level":2,"title":"路由器","slug":"路由器","link":"#路由器","children":[]}],"relativePath":"src/信息安全/网络安全协议与VPN.md","lastUpdated":1718000534000}'),l={name:"src/信息安全/网络安全协议与VPN.md"},i=a('<p><strong>第十二章 前情提要：</strong></p><table><tr><td>NTC网卡</td><td>IP</td><td>Transport传输层(TCP)</td><td>应用层（数据）</td></tr></table><h2 id="vpn是什么" tabindex="-1">VPN是什么 <a class="header-anchor" href="#vpn是什么" aria-hidden="true">#</a></h2><p><strong>Virtual Private Network：</strong> 虚拟专用网。 利用密码协议进行安全数据传输的都叫VPN</p><h2 id="ssl-tls" tabindex="-1">SSL/TLS <a class="header-anchor" href="#ssl-tls" aria-hidden="true">#</a></h2><p>在传输层与数据之间加一层SSL层，对数据进行加密</p><p>在应用层前加上技术参数（如加密方式等处理流程），国内<strong>百分之九十九</strong>网站都使用SSL协议，代价小 即<strong>端到端加密</strong></p><h2 id="ipsec-ah-esp" tabindex="-1">IPSec(AH/ESP) <a class="header-anchor" href="#ipsec-ah-esp" aria-hidden="true">#</a></h2><p>IKE：本质上使用David-哈夫曼密钥交换协议，用于解决密钥交换问题</p><p>AH：轻量级保护，只能保护数据不被修改，</p><p>ESP：重量级，保护不被修改且不被查看</p><p><strong>ESP：</strong> 封装安全载荷。 使用对称加密算法</p><ul><li><p>Encryption PC5，IDE等</p></li><li><p>Authentication HMAC-MD5-96 HMAC-SHA-1-96</p></li><li><p>鉴别首部AH</p></li><li><p>封装安全载荷ESP</p></li><li><p>加上新的IP2IP</p></li></ul><p><strong>地址到地址加密</strong> 在IP与TCP之间加密 主要应用于<em>翻墙</em></p><ul><li>传输模式 不对IP进行保护</li><li>隧道模式 添加外部IP，对原始IP进行保护</li></ul><h2 id="路由器" tabindex="-1">路由器 <a class="header-anchor" href="#路由器" aria-hidden="true">#</a></h2><p>路由器在网卡与IP之间加一层加密</p>',17),r=[i];function n(p,d,o,c,h,_){return t(),s("div",null,r)}const S=e(l,[["render",n]]);export{u as __pageData,S as default};
